var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"크아아악!!","JPN":"くうっ！！","ENG":"Aaah!","TWN":"唔啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"너, 넌 대체 뭐냐?! 어째서 클리포트 인자를 사용할 수 있는 거지?!","JPN":"な、何者だ！？\\nなぜクリフォト・ファクターを使えている！？","ENG":"W-what are you? How come you're using the Qliphoth Factors?","TWN":"妳、妳到底是什麼？！為什麼妳有辦法使用逆卡巴拉因子？！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"아, 아니 그보다 클리포트 레플리카 인자는 이론상 원본과 동일한 출력일 텐데......?","JPN":"いや、それよりもレプリカ・クリフォト・ファクターは\\n理論上、オリジナルと同じ出力のはずだが……？","ENG":"A-and Qliphoth Replica Factors should have the exact same energy output as the original ones!","TWN":"不、不對，逆卡巴拉複製因子理論上和本體的功率是一樣的啊……？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"어떻게 이런 차이가?!","JPN":"なぜこれほどの違いが！？","ENG":"How can there be so big of a difference?","TWN":"差距怎麼會這麼大？！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"동일하다고? 그건 네 생각이겠지.","JPN":"同じだと？　それはお前の思い込みだろ。","ENG":"Same energy output? You're living in a daydream.","TWN":"妳說一樣？那是妳自己的想法吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"네놈이 찍어내고 있는 그건 결국 연마되지 못한 불순물 덩어리에 불과해.","JPN":"お前がコピーしているのは、結局研磨されていない不純物の塊に過ぎない。","ENG":"What you're producing in your factories are nothing but chunks of impurities.","TWN":"你們造的那些東西，不過是些沒有研磨過的雜質堆而已。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"성능은 저질인 주제에 재활용도 힘든 조잡한 싸구려 잡철이나 마찬가지지.","JPN":"性能も悪いくせに、リサイクルすらままならない鉄くず同然だ。","ENG":"They're like cheap scrap metals. They lack in quality and are hard to use.","TWN":"就跟性能低下，難以回收再利用的粗劣廉價原料一樣。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그러니 <color=#ffd34c>진짜 강철</color>과 부딪치면 그대로 깨져나갈 수밖에.","JPN":"だから<color=#ffd34c>本物の鋼鉄</color>とぶつかれば、壊れて当然だ。","ENG":"They're bound to shatter to pieces when swung against <color=#ffd34c>real steel</color>!","TWN":"所以和<color=#ffd34c>真正的鋼鐵</color>一撞，只有粉碎的份。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"허튼 소리!","JPN":"冗談じゃない！","ENG":"That's nonsense!","TWN":"胡說八道！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"이 클리포트 레플리카 인자는 수많은 희생을 통해 만들어 낸 테라사이드 시스템의 정수다!","JPN":"このレプリカ・クリフォト・ファクターは、数多くの犠牲をもとに誕生した、テラサイドシステムの真髄だ！","ENG":"Qliphoth Replica Factors are the pinnacle of technology made whole by System Terraside! They were built upon countless sacrifices!","TWN":"逆卡巴拉複製因子是用成千上萬的犧牲者造就的特拉賽德系統精髓。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"이것이야말로 다가올 종말로부터 인류를 구원할 유일한 희망이란 말이다!","JPN":"これこそが、迫り来る終末から人類を救う唯一の希望なのだ！","ENG":"This is the one and only hope we have against the doom reserved for humanity!","TWN":"這才是能在即將到來的末日中，拯救人類的唯一希望！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"그런 것을 감히 불순물이나 찌꺼기 따위로 칭하는 건 용서 못할......","JPN":"そんなものを不純物や鉄くずなどと称するのは、許せん……","ENG":"You'll be damned for calling them impurities—","TWN":"而妳竟敢把它叫作雜質、殘渣，不可原諒……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"크아악!!","JPN":"ぐああ！！","ENG":"Aaaargh!","TWN":"唔啊啊！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"개소리를 길게도 하는군.","JPN":"バカなことを言うな。","ENG":"Please, keep your jokes to yourself.","TWN":"廢話真多呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나유빈이 그렇게 말하던가? 클리포트 인자로 인류를 구할 수 있다고?","JPN":"イチノセがそう言ったのか？　クリフォト・ファクターで人類を救えると？","ENG":"Did Na Yubin tell you? That the Qliphoth Factor will save mankind?","TWN":"是羅瑜斌那樣說的嗎？逆卡巴拉因子可以拯救人類？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"미안하지만 넌 그 녀석에게 그냥 속은 거야.","JPN":"悪いが、お前はあいつにまんまと騙されたんだ。","ENG":"I'm sorry, but that kid was just messing with you.","TWN":"很可惜，妳被他騙了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"테라사이드 시스템인지 뭔지 그 낡아빠진 가마솥에서 나온 찌꺼기야말로 네가 말한 종말을 더욱 앞당기는 독소일 뿐이다.","JPN":"テラサイドシステムとやらのおんぼろ釜から出たカスこそ、\\nお前の言う終末をさらに近づける毒素に過ぎない。","ENG":"The dregs you scraped off this old cauldron you call Terraside is nothing but poison that brings the doom of humanity forward.","TWN":"不管是特拉賽德系統還是什麼，這種從破爛大釜中撈出的殘渣，才是加快妳那末日到來的毒素。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"그, 그런......","JPN":"そ、そんな……","ENG":"Th-that...","TWN":"怎、怎麼會……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"그런 건 믿을 수 없어!","JPN":"そんなの、信じられない！","ENG":"That can't be true!","TWN":"我才不相信這種事！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"날 동요시키려 하지 마라!","JPN":"私を揺さぶるな！","ENG":"You're just trying to shake me up!","TWN":"妳別想動搖我！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"네가 믿든 안 믿든 관심 없다.","JPN":"お前が信じようが信じまいがどうでもいい。","ENG":"I don't care whether you believe me or not.","TWN":"我不在意妳相信還是不相信。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"난 그저 내 할 일을 할 뿐이지.","JPN":"私はただ、自分のやるべきことをやるだけだ。","ENG":"I'm just going to do what I have to do.","TWN":"我只是做我的工作而已。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그리고 너 같은 얼간이들이 상황을 더 악화시키기 전에 처단하는 게......","JPN":"それと、お前みたいなバカどもが、状況をさらに悪化させる前に始末するのが……","ENG":"Which, in this case, is getting rid of an idiot like you,","TWN":"而在情況更加惡化前，把妳這種笨蛋處刑掉……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"바로 내 일이다!","JPN":"私の仕事だ！","ENG":"trying to make everything worse!","TWN":"正是我的工作！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"크아아아아아악!!","JPN":"あああああ！！","ENG":"Graaah!","TWN":"呃啊啊啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"맙소사...... 실비아씨, 보고 계십니까?","JPN":"まさかこんな……シルビアさん、見ていますか？","ENG":"Good Lord... Sylvia, are you looking at this?","TWN":"天哪……希爾維亞小姐，妳看到了嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"보고 있어...... 이게 진짜라고?","JPN":"見てるわ……これはリアルなの？","ENG":"I am looking... Is this really happening?","TWN":"看到了……這是真的嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제이나...... 아니 리플레이서 퀸을 저렇게 일방적으로 밀어붙이다니......","JPN":"ジェイナ……いや、リプレイサー・クイーンをあんなに一方的に追い込むなんて……","ENG":"Jaina... I mean, Replacer Queen can't even stand straight against her attacks...","TWN":"婕娜，不……能這樣單方面地壓制克隆．女皇……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"저건 대체 누구지?","JPN":"あれはいったい誰なんだ？","ENG":"Who on earth is that?","TWN":"那到底是誰啊？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"지, 지난번 합동 작전을 진행했던 코핀 컴퍼니의 힐데 소대장입니다.","JPN":"い、以前、合同作戦を展開したコフィンカンパニーのヒルデ小隊長です。","ENG":"Sh-she's Commander Hilde of the Coffin Company. We did a joint operation with them a while back.","TWN":"她、她是上次和我們一起作戰，科芬公司的希爾德小隊長。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하, 하지만 지난번에 싸웠을 때는 저 정도 실력이 아니었습니다!","JPN":"で、でも、前回戦った時はあれほどの実力ではありませんでした。","ENG":"B-but she was nowhere near that formidable when we met last time!","TWN":"但、但是上次戰鬥的時候她的實力不是這樣的！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아무리 실력을 감추고 있었다고 해도...... 이 차이는 대체......","JPN":"実力を隠していたとしても……この違いはいったい……","ENG":"One can only do so much to hide their strength. This incomprehensible difference of strength is...","TWN":"就算再怎麼隱藏實力……這個差距到底是……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"관리국이...... 우리에게 숨기고 있는 게 생각보다 많은 모양이군.","JPN":"思ったよりも……管理局が我々に黙っていることが多いようだな。","ENG":"It seems the Administration is holding back a lot of things from us.","TWN":"管理局……隱藏的事情看來比我們想像得還要多啊。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"TERRASYS_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>【리플레이서 퀸】 병렬 재생체가 완전히 파괴되었습니다.</color>","JPN":"<color=#ffd34c>【リプレイサー・クイーン】並列再生体が完全に破壊されました。</color>","ENG":"<color=#ffd34c>Parallelly regenerated 【Replacer Queen】 has been completely destroyed.</color>","TWN":"<color=#ffd34c>【克隆．女皇】並行再生體完全被破壞了。</color>"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"TERRASYS_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>허수 에너지 간섭으로 인한 원본 육체의 대규모 손실이 발생했습니다.</color>","JPN":"<color=#ffd34c>虚数エネルギーの干渉によって、大幅な母体損傷が発生しました。</color>","ENG":"<color=#ffd34c>There was a significant physical loss due to the intervention of imaginary energy.</color>","TWN":"<color=#ffd34c>由於虛數能量的干涉，本體的肉體發生了大規模的損失。</color>"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TERRASYS_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>클리포트 레플리카 인자를 베이스로 육체를 진화 재구성합니다.</color>","JPN":"<color=#ffd34c>レプリカ・クリフォト・ファクターをもとに肉体を進化させ、組み直します。</color>","ENG":"<color=#ffd34c>Reconstructing the body based on Qliphoth Replica Factors.</color>","TWN":"<color=#ffd34c>以逆卡巴拉複製因子為基礎，進行肉體進化再構成。</color>"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TERRASYS_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>재구성 육체의 뉴런 연결강도 87%.</color>","JPN":"<color=#ffd34c>組み直した肉体のニューロン接続強度87％。</color>","ENG":"<color=#ffd34c>Neuron connection strength of the reconstructed body is currently 87%.</color>","TWN":"<color=#ffd34c>再構成肉體的神經原連接強度87%。</color>"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TERRASYS_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>주의하십시오. 뉴런 연결강도가 정상 상태로 돌아오려면 충분한 휴식이 필요합니다.</color>","JPN":"<color=#ffd34c>ご注意ください。ニューロン接続強度が正常に戻るためには、十分な休息が必要です。</color>","ENG":"<color=#ffd34c>Please take caution. The reconstructed body needs time to stabilize neuron connection.</color>","TWN":"<color=#ffd34c>請注意。神經原的連接強度要恢復到正常狀態，需要充分的休息。</color>"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TERRASYS_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>기준 이하의 뉴런 연결강도에서 재차 육체가 파괴될 경우, 일부 기억이 결손되거나 사고인지능력이 심각하게 저하될 수 있습니다.</color>","JPN":"<color=#ffd34c>基準値以下のニューロン接続強度により肉体が再度破壊された場合、\\n一部の記憶障害が発生するか、認知能力が著しく低下する恐れがあります。</color>","ENG":"<color=#ffd34c>Having the body destroyed again while neuron connection strength is below a certain point can result in a partial loss of memory and/or significant cognitive disabilities.</color>","TWN":"<color=#ffd34c>如果肉體的神經原連接強度低於標準，並再度受到破壞的場合，會出現部分記憶喪失，和認知能力明顯下降的現象。</color>"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_04"},{"id":"L8_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"아, 아직...... 아직이다!!","JPN":"ま、まだ……まだだ！！","ENG":"N-no... Not yet!","TWN":"還……還沒有！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"나는 이 정도로 죽지 않아!!","JPN":"私はこの程度では死なん！！","ENG":"I'm not done yet!","TWN":"我不會這樣就死的！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이런, 재생하는군.","JPN":"やれやれ、再生するのか。","ENG":"Ah, you're regenerating.","TWN":"該死，再生了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이 녀석도 테라사이드 시스템의 중추는 아니었던 모양인데?","JPN":"こいつもテラサイドシステムの中枢ではなかったようだな？","ENG":"She doesn't seem to be the backbone of System Terraside either.","TWN":"這傢伙好像也不是特拉賽德系統中樞的樣子？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"단순한 인자 재조합기의 역할을 할 뿐인가...... 육체를 구성하고 남은 인자는......","JPN":"単にファクター再生器の役割をしていただけか……肉体を組み立てて、残ったファクターは……","ENG":"All she does is serve as a factor recombiner. The leftover factors after the physical reconstruction...","TWN":"她只是單純的因子重組機嗎……構成肉體，然後將剩下的因子……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......저쪽으로 전송되는군.","JPN":"……あっちに転送されるのか。","ENG":"They are transferred to there.","TWN":"……傳送到那邊。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"소, 소대장!","JPN":"しょ、小隊長！","ENG":"C-Commander!","TWN":"小、小隊長！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대단해!! 리플레이서 퀸을 단숨에 쓰러트렸잖아!","JPN":"すごいよ！！　リプレイサー・クイーンを一瞬で倒しちゃった！","ENG":"That was amazing! You knocked that Replacer Queen cold like she was nothing!","TWN":"太厲害了！！竟然一擊擊敗了克隆．女皇！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"호들갑 떨지 마라, 신입.","JPN":"騒ぐな、新人。","ENG":"Don't make a fuss, Rookie.","TWN":"不要大驚小怪的，新人。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"쓰러트렸다고 해도 잠시뿐이다. 곧 다시 재생되겠지.","JPN":"倒したとしても長くはもたん。じきに再生されるだろう。","ENG":"Knocking her cold isn't the end of everything. She's going to be regenerated soon.","TWN":"我只是暫時打倒了她。她一會就會再生的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그보다 다친 곳은 없나?","JPN":"それよりケガはないか？","ENG":"Anyway, are you hurt anywhere?","TWN":"比起這個，妳沒有受傷吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나, 난 괜찮아. 하지만 선배가 아직......","JPN":"わ、私は大丈夫だよ。でも、先輩がまだ……","ENG":"I-I'm fine. B-but Shiyoon is...","TWN":"我、我沒事。但是前輩還……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"......그 녀석이라면 걱정할 것 없다.","JPN":"……あいつのことなら、心配無用だ。","ENG":"There's no need for you to be worried about him.","TWN":"……那傢伙的話不用擔心。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너와는 달리 어떤 상황에서도 자기 목숨 정도는 건사할 수 있는 녀석이니까.","JPN":"お前とは違って、どんな状況でも自分の命ぐらいは守れる奴だからな。","ENG":"Unlike you, he's capable enough to stay alive in tough situations.","TWN":"和妳不一樣，他是個不管在什麼狀況下，都很愛惜自己生命的傢伙。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건...... 그렇지.","JPN":"それは……たしかに。","ENG":"That's... right, I guess.","TWN":"那倒是……沒錯。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그보다 네게 맡길 일이 있다.","JPN":"それよりお前に頼みたいことがある。","ENG":"By the way, I have a task for you.","TWN":"話說回來，我有事情要交給妳。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"우리가 여기서 저 녀석을 상대하고 있는 동안...... 넌 저곳으로 가라.","JPN":"私たちがここであいつの相手をしている間……お前は向こうに行け。","ENG":"While we stay here dealing with that creep, you go aboard that thing.","TWN":"我們在這裡對付那個傢伙的時候……我要妳去那裡。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저곳......? 침몰한 뉴 오하이오 말하는 거야?","JPN":"向こう……？　沈没したニューオハイオのことを言ってる？","ENG":"That thing? Are you talking about that sunken ship, the New Ohio?","TWN":"那裡……？妳是說被擊沉的新俄亥俄嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그래. 그곳에 테라사이드 시스템의 중추가 있을 거다.","JPN":"そうだ、向こうにテラサイドシステムの中枢があるはずだ。","ENG":"Yes. You'll be able to find the backbone of System Terraside in there.","TWN":"沒錯。特拉賽德系統的中樞就在那裡。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그걸 파괴하면 된다.","JPN":"それを破壊すれば良い。","ENG":"Destroy it.","TWN":"把那個破壞掉就行了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"테라사이드 시스템의 중추? 나 혼자?","JPN":"テラサイドシステムの中枢？　私ひとりで？","ENG":"The backbone of System Terraside? On my own?","TWN":"特拉賽德系統的中樞？我一個人？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그래. 알고 있겠지만 이 녀석들은 재생할 때마다 더욱 강해진다.","JPN":"そうだ、気づいているだろうが、こいつらは再生するたびにさらに強くなる。","ENG":"On your own. As you may know, these things get stronger every time they regenerate.","TWN":"沒錯。妳也知道的，這些傢伙每次再生，都會變得更強。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나도 사정상 이 정도의 힘을 오랫동안 사용하지는 못해.","JPN":"私にも事情があって、これだけの力を長時間使用することはできない。","ENG":"And I won't be able to use power this intense for very long.","TWN":"我也沒辦法長時間使用這個力量。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"숫자도 계속 늘어날 테니까 아무리 내가 있다고 해도 병력을 많이 뺄 여유는 없어.","JPN":"敵もどんどん増えるだろうから、私がここにいるからって多くの兵力を他所にやる余裕もない。","ENG":"And the enemies will keep multiplying here. I can't afford to further divide our forces.","TWN":"而且他們的數量也在不斷地增加，就算我再厲害，也無法打敗這麼多人。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"내가 일을 맡길 수 있는 건 너뿐이다.","JPN":"だから、これを頼めるのはお前だけだ。","ENG":"You're the only person I can entrust this task with.","TWN":"能夠讓我交付這個任務的人，就只有妳了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그러니까...... 서둘러라!","JPN":"わかったなら……急げ！","ENG":"So hurry!","TWN":"所以……快去吧！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......아, 알았어!","JPN":"……りょ、了解。","ENG":"O-okay!","TWN":"……是，我知道了！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맡겨둬!","JPN":"まかせて！","ENG":"Leave it to me!","TWN":"交給我吧！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};